import{_ as a,o as t,c as s,ag as o}from"./chunks/framework.CHQlKclR.js";const p=JSON.parse('{"title":"SD Card Utilities","description":"","frontmatter":{},"headers":[],"relativePath":"api/sdcard.md","filePath":"api/sdcard.md"}'),i={name:"api/sdcard.md"};function r(n,e,d,l,c,h){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="sd-card-utilities" tabindex="-1">SD Card Utilities <a class="header-anchor" href="#sd-card-utilities" aria-label="Permalink to &quot;SD Card Utilities&quot;">​</a></h1><p>Vortex provides helper functions for interacting with the V5 SD Card (MicroSD). These are primarily used by the Autonomous Selector but can be used for custom telemetry logging.</p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><p>All SD card functions reside in the <code>vortex::as</code> namespace (as part of the autonomous selector system).</p><h3 id="checking-for-sd-card" tabindex="-1">Checking for SD Card <a class="header-anchor" href="#checking-for-sd-card" aria-label="Permalink to &quot;Checking for SD Card&quot;">​</a></h3><p>You can check if an SD card is installed using a utility constant:</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vortex</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">util</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::SD_CARD_ACTIVE) {</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // Write something to the card</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><h3 id="persistent-autonomous-selection" tabindex="-1">Persistent Autonomous Selection <a class="header-anchor" href="#persistent-autonomous-selection" aria-label="Permalink to &quot;Persistent Autonomous Selection&quot;">​</a></h3><p>Vortex uses the SD card to remember which autonomous routine you selected, even after a power cycle. This prevents you from forgetting to set your auton during a frantic match.</p><h3 id="autonomous-logs" tabindex="-1">Autonomous Logs <a class="header-anchor" href="#autonomous-logs" aria-label="Permalink to &quot;Autonomous Logs&quot;">​</a></h3><p>While not highly exposed, the SD card system tracks initialization states to ensure the selector only runs when intended.</p><h2 id="api-reference" tabindex="-1">API Reference <a class="header-anchor" href="#api-reference" aria-label="Permalink to &quot;API Reference&quot;">​</a></h2><h3 id="void-auton-selector-initialize" tabindex="-1"><code>void auton_selector_initialize()</code> <a class="header-anchor" href="#void-auton-selector-initialize" aria-label="Permalink to &quot;`void auton_selector_initialize()`&quot;">​</a></h3><p>Reads the previously saved autonomous page from the SD card (<code>/usd/vortex_auton.txt</code>) and sets the selector to that page.</p><h3 id="void-auto-sd-update" tabindex="-1"><code>void auto_sd_update()</code> <a class="header-anchor" href="#void-auto-sd-update" aria-label="Permalink to &quot;`void auto_sd_update()`&quot;">​</a></h3><p>Writes the current autonomous page selection to the SD card.</p><h3 id="bool-enabled" tabindex="-1"><code>bool enabled()</code> <a class="header-anchor" href="#bool-enabled" aria-label="Permalink to &quot;`bool enabled()`&quot;">​</a></h3><p>Returns <code>true</code> if the autonomous selector system is properly initialized and has access to its state.</p><hr><div class="warning custom-block"><p class="custom-block-title">Format your SD card</p><p>Ensure your SD card is formatted to <strong>FAT32</strong> for compatibility with the VEX V5 Brain. Cards larger than 32GB may require special formatting tools.</p></div>',21)])])}const m=a(i,[["render",r]]);export{p as __pageData,m as default};
